begin;
create table public.executive_briefs(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),brief_date date not null,payload jsonb not null,source_references text[] not null default '{}',generator_version text not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),unique(workspace_id,domain_id),unique(workspace_id,brief_date));
create table public.interview_preparations(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),application_domain_id text not null,status text not null,payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id));
create table public.negotiation_planners(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),application_domain_id text not null,status text not null,payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id));
create table public.decision_workspaces(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),title text not null,status text not null,payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id));
create table public.executive_notes(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),title text not null,markdown text not null,tags text[] not null default '{}',evidence_references text[] not null default '{}',atlas_references text[] not null default '{}',ledger_entry_ids text[] not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id));
create table public.executive_tasks(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),title text not null,description text,deadline timestamptz,priority text not null,status text not null,reminder timestamptz,related_opportunity_id text,related_company_id text,related_application_id text,related_memory_id text,related_decision_id text,payload jsonb not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id));
create table public.executive_follow_ups(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),task_id uuid not null,subject text not null,due_at timestamptz not null,status text not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,foreign key(task_id) references public.executive_tasks(id),unique(workspace_id,domain_id));
do $$declare t text;begin foreach t in array array['executive_briefs','interview_preparations','negotiation_planners','decision_workspaces','executive_notes','executive_tasks','executive_follow_ups'] loop execute format('alter table public.%I enable row level security',t);execute format('create policy %I on public.%I for select to authenticated using(public.is_active_workspace_member(workspace_id))',t||'_read',t);execute format('create policy %I on public.%I for insert to authenticated with check(public.is_active_workspace_member(workspace_id))',t||'_insert',t);execute format('create policy %I on public.%I for update to authenticated using(public.is_active_workspace_member(workspace_id)) with check(public.is_active_workspace_member(workspace_id))',t||'_update',t);end loop;end$$;
grant select,insert,update on public.executive_briefs,public.interview_preparations,public.negotiation_planners,public.decision_workspaces,public.executive_notes,public.executive_tasks,public.executive_follow_ups to authenticated;revoke delete on all tables in schema public from authenticated;revoke all on all tables in schema public from anon;
create index executive_briefs_workspace_date_idx on public.executive_briefs(workspace_id,brief_date desc);create index interview_preparations_workspace_status_idx on public.interview_preparations(workspace_id,status);create index negotiation_planners_workspace_status_idx on public.negotiation_planners(workspace_id,status);create index executive_notes_workspace_tags_idx on public.executive_notes using gin(tags);create index executive_tasks_workspace_deadline_idx on public.executive_tasks(workspace_id,status,deadline);create index executive_follow_ups_workspace_due_idx on public.executive_follow_ups(workspace_id,status,due_at);
commit;
